question:
What is the output of the following code snippet?

```cpp
#include <iostream>
using namespace std;

class Base {};
class Derived : public Base {};

int main() {
    try {
        throw Derived();
    }
    catch (Base& b) {
        cout << "Caught Base";
    }
    catch (Derived& d) {
        cout << "Caught Derived";
    }
    return 0;
}
```
